sql:
SELECT team_id, SUM(wins) AS total_wins
FROM match_results
GROUP BY team_id;

SELECT t.team_name, d.division_name
FROM teams t
INNER JOIN divisions d ON t.division_id = d.division_id;

external_knowledge:
- 'majestic ships' refers to the rugby teams;
- 'navigated through the densest crowds' means teams that have drawn the largest number of spectators over all their matches;
- 'size of these waves' refers to the total attendance figures for each team;
- 'positions in the stormy seas of popularity' refers to the rank of each team based on their total attendance.

sql:
SELECT AVG(attendance) AS average_crowd_size
FROM matches
WHERE venue_id = 1;
